import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * A professional weather card component displaying current conditions and a 5-day forecast.
 * Built with ggui design system primitives and semantic tokens.
 */
export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "☁️", high: 25, low: 19 },
    { day: "Thu", icon: "🌧️", high: 22, low: 18 },
    { day: "Fri", icon: "⛅", high: 26, low: 21 }
  ]
}: Props) {

  // Simple emoji mapping for the main display based on the condition string
  const getConditionEmoji = (cond: string) => {
    const c = cond?.toLowerCase() ?? "";
    if (c.includes("sun") || c.includes("clear")) return "☀️";
    if (c.includes("cloud")) return "☁️";
    if (c.includes("rain") || c.includes("show")) return "🌧️";
    if (c.includes("storm")) return "⛈️";
    if (c.includes("snow")) return "❄️";
    if (c.includes("mist") || c.includes("fog")) return "🌫️";
    return "🌡️";
  };

  return (
    <Card 
      padding={24} 
      shadow="md" 
      radius="xl" 
      border={true}
    >
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city ?? "Unknown City"}
            </Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Current Conditions
            </Text>
          </Stack>
          <Box 
            padding={12} 
            borderRadius="var(--ggui-shape-radius-full, 9999px)" 
            background="var(--ggui-color-primary-50, #f0f9ff)"
          >
            <Text size="3xl" aria-hidden="true">
              {getConditionEmoji(condition)}
            </Text>
          </Box>
        </Stack>

        {/* Temperature & Main Condition Section */}
        <Stack direction="horizontal" align="end" justify="start" gap={12}>
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
            {Math.round(temperature ?? 0)}°{unit ?? "C"}
          </Heading>
          <Box paddingY={8}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {condition ?? "Clear"}
            </Text>
          </Box>
        </Stack>

        {/* Stats Section */}
        <Box 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          padding={16} 
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" justify="around" align="center">
            <Stack align="center" gap={4}>
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text weight="bold" size="lg">{humidity ?? 0}%</Text>
            </Stack>
            <Divider orientation="vertical" margin={12} color="var(--ggui-color-outline, #d4d4d8)" />
            <Stack align="center" gap={4}>
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text weight="bold" size="lg">{windSpeed ?? 0} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        {/* 5-Day Forecast Section */}
        <Stack gap={16}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            5-Day Forecast
          </Text>
          <Stack direction="horizontal" justify="between" gap={4} wrap={false}>
            {(forecast ?? []).slice(0, 5).map((item, index) => (
              <Box 
                key={index}
                style={{ flex: 1 }}
                paddingY={8}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Stack align="center" gap={8}>
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.day ?? "Day"}
                  </Text>
                  <Text size="xl" aria-hidden="true">
                    {item.icon ?? "🌡️"}
                  </Text>
                  <Stack gap={2} align="center">
                    <Text size="sm" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                      {item.high ?? 0}°
                    </Text>
                    <Text size="xs" color="var(--ggui-color-neutral-500, #6b7280)">
                      {item.low ?? 0}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Box,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions?: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels?: string[];
  /** Submit callback */
  submit?: (payload: any) => void;
}

export default function GeneratedComponent({
  featureOptions = [
    "Dashboard Analytics",
    "Team Collaboration",
    "API Integration",
    "Custom Workflows",
    "Mobile App",
    "AI Assistance"
  ],
  satisfactionLabels = [
    "Very Unsatisfied",
    "Unsatisfied",
    "Neutral",
    "Satisfied",
    "Very Satisfied"
  ],
  submit
}: Props) {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  const totalSteps = 5; // 4 input steps + 1 review step

  // Validation Logic
  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateStep1 = () => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!isEmailValid(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const canGoNext = () => {
    if (step === 1) return formData.name.trim() !== '' && isEmailValid(formData.email);
    if (step === 2) return formData.satisfaction !== '';
    return true;
  };

  const handleNext = () => {
    if (step === 1 && !validateStep1()) return;
    setStep((prev) => Math.min(prev + 1, totalSteps));
  };

  const handleBack = () => {
    setStep((prev) => Math.max(prev - 1, 1));
  };

  const handleToggleFeature = (feature: string, checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      features: checked 
        ? [...prev.features, feature] 
        : prev.features.filter((f) => f !== feature)
    }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      const payload = {
        ...formData,
        satisfaction: parseInt(formData.satisfaction, 10)
      };
      submit?.(payload);
    } catch (err) {
      console.error("Submission failed", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Agent data listener
  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) {
        setFormData((prev) => ({ ...prev, ...event.detail }));
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  return (
    <Container maxWidth="md" padding={16}>
      <Stack gap={24}>
        {/* Header & Progress */}
        <Stack gap={8}>
          <Heading level={2}>Customer Feedback Survey</Heading>
          <Stack direction="horizontal" justify="between" align="end">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {step} of {totalSteps}
            </Text>
            <Text variant="caption" color="var(--ggui-color-primary-600)">
              {Math.round((step / totalSteps) * 100)}% Complete
            </Text>
          </Stack>
          <Progress value={step} max={totalSteps} variant="primary" size="sm" />
        </Stack>

        <Card padding={24} shadow="md" radius="xl">
          <Stack gap={32}>
            {/* Step 1: Identity */}
            {step === 1 && (
              <Stack gap={16} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Let's get started</Heading>
                <Input
                  label="Full Name"
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => setFormData({ ...formData, name: val })}
                  error={errors.name}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData({ ...formData, email: val })}
                  error={errors.email}
                  required
                />
              </Stack>
            )}

            {/* Step 2: Satisfaction */}
            {step === 2 && (
              <Stack gap={16} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>How satisfied are you with our service?</Heading>
                <RadioGroup
                  label="Select a rating"
                  value={formData.satisfaction}
                  onChange={(val) => setFormData({ ...formData, satisfaction: val })}
                  options={satisfactionLabels.map((label, index) => ({
                    value: (index + 1).toString(),
                    label: `${index + 1} - ${label}`,
                  }))}
                />
              </Stack>
            )}

            {/* Step 3: Features */}
            {step === 3 && (
              <Stack gap={16} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Which features are you most interested in?</Heading>
                <Stack gap={12}>
                  {featureOptions.map((option) => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={formData.features.includes(option)}
                      onChange={(checked) => handleToggleFeature(option, checked)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {/* Step 4: Comments */}
            {step === 4 && (
              <Stack gap={16} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Any additional comments?</Heading>
                <TextArea
                  label="Your Feedback"
                  placeholder="Tell us what's on your mind..."
                  value={formData.comments}
                  onChange={(val) => setFormData({ ...formData, comments: val })}
                  maxLength={500}
                  showCount
                  rows={6}
                />
              </Stack>
            )}

            {/* Step 5: Review */}
            {step === 5 && (
              <Stack gap={20} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Review your answers</Heading>
                <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius={12}>
                  <Stack gap={16}>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Contact Info</Text>
                      <Text weight="medium">{formData.name} ({formData.email})</Text>
                    </Stack>
                    <Divider margin={8} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                      <Text weight="medium">
                        {formData.satisfaction} / 5 ({satisfactionLabels[parseInt(formData.satisfaction) - 1]})
                      </Text>
                    </Stack>
                    <Divider margin={8} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Interested Features</Text>
                      <Text weight="medium">
                        {formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}
                      </Text>
                    </Stack>
                    <Divider margin={8} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Additional Comments</Text>
                      <Text weight="medium">{formData.comments || 'No comments provided'}</Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}

            {/* Navigation */}
            <Stack direction="horizontal" gap={12} justify="end">
              {step > 1 && (
                <Button variant="outline" onClick={handleBack} disabled={isSubmitting}>
                  Back
                </Button>
              )}
              {step < totalSteps ? (
                <Button 
                  variant="primary" 
                  onClick={handleNext} 
                  disabled={!canGoNext()}
                  rightIcon={<Text size="sm">→</Text>}
                >
                  Next
                </Button>
              ) : (
                <Button 
                  variant="primary" 
                  onClick={handleSubmit} 
                  loading={isSubmitting}
                >
                  Submit Survey
                </Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Box,
  Divider,
  Container,
  Icon,
  Spacer
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  /** Array of tasks with id, title, priority, assignee initials, column ID, and optional dueDate */
  tasks: Task[];
  /** Column definitions */
  columns: Column[];
  /** Action Contract callback */
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: Partial<Task> }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    tasks = [], 
    columns = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' }
    ],
    onTaskUpdate 
  } = props;

  const [localTasks, setLocalTasks] = useState<Task[]>(tasks);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');

  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter(t => t.column === 'done').length;

  const handleMoveTask = (taskId: string, targetColumn: string) => {
    const updated = localTasks.map(t => t.id === taskId ? { ...t, column: targetColumn } : t);
    setLocalTasks(updated);
    onTaskUpdate?.({
      action: 'move',
      taskId,
      data: { column: targetColumn }
    });
  };

  const handleCreateTask = (columnId: string) => {
    if (!newTitle.trim()) return;

    const id = `task-${Date.now()}`;
    const newTask: Task = {
      id,
      title: newTitle,
      priority: newPriority,
      column: columnId,
      assignee: '??'
    };

    setLocalTasks([...localTasks, newTask]);
    onTaskUpdate?.({
      action: 'create',
      data: newTask
    });

    setAddingToColumn(null);
    setNewTitle('');
    setNewPriority('medium');
  };

  const handleUpdateTitle = (taskId: string, title: string) => {
    const updated = localTasks.map(t => t.id === taskId ? { ...t, title } : t);
    setLocalTasks(updated);
    onTaskUpdate?.({
      action: 'edit',
      taskId,
      data: { title }
    });
    setEditingTaskId(null);
  };

  const getPriorityVariant = (p?: string) => {
    switch (p) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'info';
      default: return 'default';
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4, 16px)" shadow="sm" radius="lg" border>
          <Stack direction="horizontal" align="center" justify="between">
            <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" align="center">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Total Tasks</Text>
                <Heading level={4}>{totalTasks}</Heading>
              </Stack>
              <Divider orientation="vertical" margin="var(--ggui-spacing-4, 16px)" />
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Completed</Text>
                <Heading level={4}>{completedTasks}</Heading>
              </Stack>
            </Stack>
            <Box background="var(--ggui-color-primary-50)" paddingX="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-2, 8px)" borderRadius="var(--ggui-shape-radius-full)">
              <Text variant="label" color="var(--ggui-color-primary-700)">
                {totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0}% Done
              </Text>
            </Box>
          </Stack>
        </Card>

        {/* Board Columns */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" align="start" wrap>
          {columns.map((col) => {
            const columnTasks = localTasks.filter(t => t.column === col.id);

            return (
              <Box 
                key={col.id} 
                style={{ flex: '1 1 300px', minWidth: '300px' }}
                background="var(--ggui-color-surfaceVariant)"
                padding="var(--ggui-spacing-4, 16px)"
                borderRadius="var(--ggui-shape-radius-xl)"
              >
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={5}>{col.name}</Heading>
                    <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
                  </Stack>

                  <Stack gap="var(--ggui-spacing-3, 12px)">
                    {columnTasks.map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-4, 16px)" shadow="sm" radius="md">
                        <Stack gap="var(--ggui-spacing-3, 12px)">
                          <Stack direction="horizontal" justify="between" align="start">
                            <Badge variant={getPriorityVariant(task.priority)} size="sm" pill={false}>
                              {task.priority?.toUpperCase()}
                            </Badge>
                            <Select
                              size="sm"
                              value={task.column}
                              onChange={(val) => handleMoveTask(task.id!, val)}
                              options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                              aria-label="Move task"
                            />
                          </Stack>

                          {editingTaskId === task.id ? (
                            <Stack gap="var(--ggui-spacing-2, 8px)">
                              <Input
                                label="Task Title"
                                value={task.title}
                                autoFocus
                                onChange={(val) => {
                                  const updated = localTasks.map(t => t.id === task.id ? { ...t, title: val } : t);
                                  setLocalTasks(updated);
                                }}
                              />
                              <Button size="sm" onClick={() => handleUpdateTitle(task.id!, task.title || '')}>
                                Save
                              </Button>
                            </Stack>
                          ) : (
                            <Text 
                              variant="bodySmall" 
                              weight="medium"
                              style={{ cursor: 'pointer', transition: 'color 200ms ease' }}
                              onPress={() => setEditingTaskId(task.id!)}
                            >
                              {task.title}
                            </Text>
                          )}

                          <Stack direction="horizontal" align="center" justify="between">
                            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                              <Avatar name={task.assignee} size="xs" />
                              {task.dueDate && (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.dueDate}
                                </Text>
                              )}
                            </Stack>
                            <Button 
                              variant="ghost" 
                              size="xs" 
                              leftIcon={<Icon name="settings" size={14} />} 
                              onClick={() => setEditingTaskId(task.id!)}
                              aria-label="Edit task"
                            />
                          </Stack>
                        </Stack>
                      </Card>
                    ))}

                    {addingToColumn === col.id ? (
                      <Card padding="var(--ggui-spacing-4, 16px)" border borderStyle="dashed">
                        <Stack gap="var(--ggui-spacing-4, 16px)">
                          <Input
                            label="Task Name"
                            placeholder="What needs to be done?"
                            value={newTitle}
                            onChange={setNewTitle}
                            required
                          />
                          <Select
                            label="Priority"
                            value={newPriority}
                            onChange={(v) => setNewPriority(v as any)}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' }
                            ]}
                          />
                          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                            <Button size="sm" fullWidth onClick={() => handleCreateTask(col.id!)}>Add</Button>
                            <Button size="sm" variant="ghost" onClick={() => setAddingToColumn(null)}>Cancel</Button>
                          </Stack>
                        </Stack>
                      </Card>
                    ) : (
                      <Button 
                        variant="ghost" 
                        fullWidth 
                        leftIcon={<Icon name="plus" size={16} />}
                        onClick={() => setAddingToColumn(col.id!)}
                      >
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Input, 
  Badge, 
  Divider, 
  Spacer 
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to semantic badge variants and custom accent colors.
 */
const getCategoryConfig = (category: string = '') => {
  const cat = category.toLowerCase();
  if (cat.includes('nonmetal')) return { variant: 'primary' as const, color: 'var(--ggui-color-primary-500)' };
  if (cat.includes('noble')) return { variant: 'info' as const, color: 'var(--ggui-color-info-600)' };
  if (cat.includes('alkali metal')) return { variant: 'error' as const, color: 'var(--ggui-color-error-600)' };
  if (cat.includes('alkaline earth')) return { variant: 'warning' as const, color: 'var(--ggui-color-warning-600)' };
  if (cat.includes('metalloid')) return { variant: 'success' as const, color: 'var(--ggui-color-success-600)' };
  if (cat.includes('halogen')) return { variant: 'info' as const, color: 'var(--ggui-color-info-400)' };
  if (cat.includes('transition metal')) return { variant: 'default' as const, color: 'var(--ggui-color-neutral-500)' };
  if (cat.includes('post-transition')) return { variant: 'secondary' as const, color: 'var(--ggui-color-neutral-400)' };
  if (cat.includes('lanthanide')) return { variant: 'info' as const, color: 'var(--ggui-color-info-300)' };
  if (cat.includes('actinide')) return { variant: 'error' as const, color: 'var(--ggui-color-error-400)' };
  return { variant: 'default' as const, color: 'var(--ggui-color-neutral-300)' };
};

export default function GeneratedComponent({ elements = [] }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    const query = search.toLowerCase().trim();
    if (!query) return elements;
    return elements.filter(
      (el) => 
        el.name?.toLowerCase().includes(query) || 
        el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, search]);

  // Extract unique categories for the legend
  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach(el => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set).sort();
  }, [elements]);

  const handleElementClick = (el: ElementData) => {
    setSelected(el);
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        {/* Header and Search */}
        <Stack gap={16}>
          <Stack direction="horizontal" align="center" justify="between">
            <Heading level={1} color="var(--ggui-color-onSurface)">Periodic Table</Heading>
            <Box width="300px">
              <Input 
                label="Search Elements"
                placeholder="Name or Symbol (e.g. Au)" 
                value={search} 
                onChange={setSearch} 
              />
            </Box>
          </Stack>

          {/* Category Legend */}
          <Stack direction="horizontal" gap={12} wrap>
            {categories.map((cat) => {
              const config = getCategoryConfig(cat);
              return (
                <Stack key={cat} direction="horizontal" gap={6} align="center">
                  <Box 
                    width={12} 
                    height={12} 
                    borderRadius="var(--ggui-shape-radius-sm)" 
                    background={config.color} 
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{cat}</Text>
                </Stack>
              );
            })}
          </Stack>
        </Stack>

        {/* Periodic Grid Container */}
        <Box 
          style={{ 
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)'
          }}
        >
          <div 
            style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(18, minmax(50px, 1fr))', 
              gridAutoRows: 'minmax(64px, auto)',
              gap: '4px',
              minWidth: '1000px'
            }}
          >
            {(elements ?? []).map((el, idx) => {
              const isMatch = filteredElements.some(f => f.atomicNumber === el.atomicNumber);
              const isSelected = selected?.atomicNumber === el.atomicNumber;
              const { color } = getCategoryConfig(el.category);

              return (
                <button
                  key={`${el.atomicNumber}-${idx}`}
                  onClick={() => handleElementClick(el)}
                  aria-label={`${el.name}, atomic number ${el.atomicNumber}`}
                  style={{
                    all: 'unset',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    position: 'relative',
                    gridColumn: el.col,
                    gridRow: el.row,
                    padding: '6px',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)'}`,
                    backgroundColor: isSelected ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                    opacity: isMatch ? 1 : 0.2,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                    transition: 'all 200ms ease-in-out',
                    boxSizing: 'border-box'
                  }}
                >
                  <Text 
                    variant="caption" 
                    size="xs" 
                    color="var(--ggui-color-onSurfaceVariant)"
                    style={{ position: 'absolute', top: '4px', left: '6px' }}
                  >
                    {el.atomicNumber}
                  </Text>
                  <Spacer size="flex" />
                  <Text 
                    weight="bold" 
                    align="center" 
                    size="lg"
                    color={color}
                  >
                    {el.symbol}
                  </Text>
                  <Text 
                    variant="caption" 
                    align="center" 
                    truncate
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    {el.name}
                  </Text>
                </button>
              );
            })}
          </div>
        </Box>

        {/* Detail Panel */}
        <Box 
          style={{ 
            minHeight: '200px',
            animation: 'ggui-fadeIn 300ms ease-out'
          }}
        >
          {selected ? (
            <Card padding={32} shadow="md" radius="xl" border>
              <Stack gap={24}>
                <Stack direction="horizontal" justify="between" align="start">
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-primary-600)">Atomic Number {selected.atomicNumber}</Text>
                    <Heading level={2} color="var(--ggui-color-onSurface)">{selected.name}</Heading>
                    <Badge variant={getCategoryConfig(selected.category).variant} size="lg">
                      {selected.category ?? 'Unknown'}
                    </Badge>
                  </Stack>
                  <Box 
                    padding={24} 
                    borderRadius="var(--ggui-shape-radius-xl)" 
                    background="var(--ggui-color-surfaceVariant)"
                    style={{ border: '2px solid var(--ggui-color-outline)' }}
