                      weight="bold" 
                      size="4xl" 
                      color={getCategoryConfig(selected.category).color}
                    >
                      {selected.symbol}
                    </Text>
                  </Box>
                </Stack>

                <Divider margin={8} />

                <Stack direction="horizontal" gap={48} wrap>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurface)">
                      {selected.atomicWeight ?? 'N/A'} u
                    </Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Group & Period</Text>
                    <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurface)">
