              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                Select an element from the table to view detailed properties.
              </Text>
            </Box>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Box,
  Card,
  Container,
  Stack,
  Text,
  Heading,
  Button,
  Badge,
  Icon,
  Divider,
  Tabs,
  Table,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Product {
  id?: string;
  name?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  stock?: number;
  description?: string;
  specifications?: any[];
  reviews?: any[];
}

interface Props {
  /** Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[] */
  product: Product;
  /** Action callback for adding item to cart */
  addToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  product = {
    id: 'prod-001',
    name: 'Wireless Noise-Cancelling Headphones',
    price: 249.99,
    currency: 'USD',
    rating: 4.3,
    reviewCount: 128,
    stock: 12,
    description: 'Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.',
    specifications: [
      { key: 'Brand', value: 'AudioMax' },
      { key: 'Battery Life', value: '30 hours' },
    ],
    reviews: [
      {
        author: 'Alex M.',
        rating: 5,
        text: 'Best headphones I have ever owned. The noise cancellation is incredible.',
        date: '2026-03-01',
      },
    ],
  },
  addToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stockLevel = product.stock ?? 0;
  const isOutOfStock = stockLevel <= 0;
  const isLowStock = stockLevel > 0 && stockLevel <= 5;

  const handleIncrement = () => {
    if (quantity < stockLevel) setQuantity((prev) => prev + 1);
  };

  const handleDecrement = () => {
    if (quantity > 1) setQuantity((prev) => prev - 1);
  };

  const handleAddToCart = () => {
    if (addToCart && product.id) {
      addToCart({ productId: product.id, quantity });
    }
  };

  // Helper to render stars
  const renderStars = (rating: number = 0) => {
    return (
      <Stack direction="horizontal" gap={2} align="center">
        {[1, 2, 3, 4, 5].map((star) => (
          <Icon
            key={star}
            name="check"
            size={16}
            color={star <= Math.round(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'}
          />
        ))}
      </Stack>
    );
  };

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY={16}>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {product.description ?? 'No description available.'}
          </Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY={16}>
          <Table
            bordered
            columns={[
              { key: 'key', header: 'Feature', width: '30%' },
              { key: 'value', header: 'Details' },
            ]}
            data={(product.specifications ?? []) as any[]}
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: `Reviews (${product.reviewCount ?? 0})`,
      content: (
        <Stack gap={16} paddingY={16}>
          {(product.reviews ?? []).map((review: any, idx: number) => (
            <Card key={idx} padding={16} shadow="none" border>
              <Stack gap={8}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label" weight="semibold">
                    {review.author ?? 'Anonymous'}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                    {review.date ?? ''}
                  </Text>
                </Stack>
                {renderStars(review.rating)}
                <Text variant="bodySmall">{review.text ?? ''}</Text>
              </Stack>
            </Card>
          ))}
          {(product.reviews?.length ?? 0) === 0 && (
            <Text variant="bodySmall" align="center" color="var(--ggui-color-neutral-500, #6b7280)">
              No reviews yet.
            </Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        {/* Top Section */}
        <Stack direction="horizontal" gap={32} align="start" wrap>
          {/* Image Placeholder */}
          <Box
            style={{
              flex: '1 1 400px',
              height: '400px',
              background: 'var(--ggui-color-primary-50, #f0f9ff)',
              border: '2px dashed var(--ggui-color-primary-200, #bae6fd)',
              borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <Stack align="center" gap={12}>
              <Icon name="settings" size={48} color="var(--ggui-color-primary-400, #38bdf8)" />
              <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">
                {product.name ?? 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Details */}
          <Stack style={{ flex: '1 1 300px' }} gap={20}>
            <Stack gap={8}>
              <Badge
                variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}
                size="sm"
              >
                {isOutOfStock ? 'Out of Stock' : isLowStock ? `Only ${stockLevel} Left!` : 'In Stock'}
              </Badge>
              <Heading level={1}>{product.name ?? 'Product Name'}</Heading>
              <Stack direction="horizontal" gap={8} align="center">
                {renderStars(product.rating)}
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  ({product.reviewCount ?? 0} reviews)
                </Text>
              </Stack>
            </Stack>

            <Divider margin={4} />

            <Stack gap={4}>
              <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
                Price
              </Text>
              <Text size="3xl" weight="bold" color="var(--ggui-color-primary-700, #0369a1)">
                {product.currency ?? '$'}
                {(product.price ?? 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}
              </Text>
            </Stack>

            <Spacer size={8} />

            {/* Quantity and Actions */}
            <Card padding={20} radius="xl" background="var(--ggui-color-surfaceVariant, #f4f4f5)" border={false}>
              <Stack gap={16}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label">Quantity</Text>
                  <Stack direction="horizontal" gap={12} align="center">
                    <Button
                      variant="outline"
                      size="sm"
                      onPress={handleDecrement}
                      disabled={quantity <= 1 || isOutOfStock}
                      aria-label="Decrease quantity"
                    >
                      <Icon name="minus" size={14} />
                    </Button>
                    <Text weight="semibold" style={{ minWidth: '2ch', textAlign: 'center' }}>
                      {quantity}
                    </Text>
                    <Button
                      variant="outline"
                      size="sm"
                      onPress={handleIncrement}
                      disabled={quantity >= stockLevel || isOutOfStock}
                      aria-label="Increase quantity"
                    >
                      <Icon name="plus" size={14} />
                    </Button>
                  </Stack>
                </Stack>

                <Button
                  variant="primary"
                  size="lg"
                  fullWidth
                  disabled={isOutOfStock}
                  onPress={handleAddToCart}
                  leftIcon={<Icon name="check" size={20} />}
                >
                  {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
                </Button>
              </Stack>
            </Card>
          </Stack>
        </Stack>

        {/* Tabs Section */}
        <Box>
          <Tabs
            variant="line"
            activeKey={activeTab}
            onChange={setActiveTab}
            items={tabItems}
          />
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Badge,
  Button,
  Input,
  Box,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action callback for sending a message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Team Chat',
  currentUser = 'You',
  participantCount = 0,
  messages = [],
  sendMessage
}: Props) {
  const [inputValue, setInputValue] = useState('');
  const scrollBottomRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom of message list on mount and when messages update
  useEffect(() => {
    scrollBottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Stream Contract: Listener for live agent data updates
  useEffect(() => {
    const handleAgentData = (event: any) => {
      // Logic to handle potential incoming data from the agent stream
      console.debug('ggui:agent-data received:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleSend = () => {
    const textToSend = inputValue.trim();
    if (!textToSend) return;

    // Action Contract: Wire the sendMessage callback
    if (sendMessage) {
      sendMessage({
        text: textToSend,
        timestamp: new Date().toISOString(),
      });
    }
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card
      padding={0}
      shadow="md"
      radius="xl"
      border
      style={{
        height: '100%',
        minHeight: '600px',
        maxHeight: '900px',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)'
      }}
    >
      {/* Header section with title and participant count */}
      <Box
        padding={16}
        background="var(--ggui-color-primary-50, #f0f9ff)"
        style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
      >
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" align="center" gap={12}>
            <Heading level={3} color="var(--ggui-color-primary-900, #0c4a6e)">
              {title ?? 'Conversation'}
            </Heading>
            {(participantCount ?? 0) > 0 && (
              <Badge variant="primary" size="sm" pill>
                {participantCount} participants
              </Badge>
            )}
          </Stack>
          <Stack direction="horizontal" align="center" gap={4}>
            <Box
              borderRadius="50%"
              style={{
                width: 8,
                height: 8,
                backgroundColor: 'var(--ggui-color-success-500, #22c55e)'
              }}
            />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live
            </Text>
          </Stack>
        </Stack>
      </Box>

      {/* Scrollable message area */}
      <Box
        padding={16}
        style={{
          flex: 1,
          overflowY: 'auto',
          background: 'var(--ggui-color-surface, #fafafa)'
        }}
      >
        <Stack gap={16}>
          {messages.map((msg, index) => {
            const isMe = msg.sender === currentUser;
            const isConsecutive = index > 0 && messages[index - 1].sender === msg.sender;
            const timeString = msg.timestamp
              ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
              : '';

            return (
              <Stack
                key={`${msg.timestamp}-${index}`}
                align={isMe ? 'end' : 'start'}
                gap={4}
                style={{
                  marginTop: isConsecutive ? -8 : 0,
                  transition: 'transform 200ms ease',
                  animation: 'ggui-slideInUp 200ms ease-out'
                }}
              >
                {!isMe && !isConsecutive && (
                  <Text
                    variant="label"
                    size="xs"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{ marginLeft: 4 }}
                  >
                    {msg.sender ?? 'Guest'}
                  </Text>
                )}
                <Box
                  paddingX={14}
                  paddingY={10}
                  borderRadius={12}
                  background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                  style={{
                    maxWidth: '80%',
                    boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                    borderBottomRightRadius: isMe ? 2 : 12,
                    borderBottomLeftRadius: isMe ? 12 : 2
                  }}
                >
                  <Stack gap={2}>
                    <Text
                      variant="body"
                      size="sm"
                      color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {msg.text ?? ''}
                    </Text>
                    <Text
                      variant="caption"
                      size="xs"
                      align="right"
                      color={isMe ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                    >
                      {timeString}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            );
          })}
          <div ref={scrollBottomRef} aria-hidden="true" />
        </Stack>
      </Box>

      {/* Message input area */}
      <Box
        padding={16}
        background="var(--ggui-color-surface, #fafafa)"
        style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
      >
        <Stack gap={8}>
          <Text
            as="label"
            htmlFor="chat-message-input"
            variant="label"
            size="xs"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Compose Message
          </Text>
          <Stack direction="horizontal" align="end" gap={12}>
            <Box style={{ flex: 1 }}>
              <Input
                id="chat-message-input"
                label="Message"
                placeholder="Type your message here..."
                value={inputValue}
                onChange={setInputValue}
                onKeyDown={handleKeyDown}
                size="md"
                required
              />
            </Box>
            <Button
              variant="primary"
              size="md"
              disabled={!inputValue.trim()}
              onClick={handleSend}
              aria-label="Send Message"
              style={{ minWidth: '80px' }}
            >
              Send
            </Button>
          </Stack>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Spacer,
  Badge,
  Icon,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<StockData>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated
}: Props) {
  const [stocks, setStocks] = useState<StockData[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isConnecting, setIsConnecting] = useState(false);

  // Sync state with props when they change
  useEffect(() => {
    setStocks(initialStocks);
  }, [initialStocks]);

  useEffect(() => {
    setLastUpdated(initialLastUpdated);
  }, [initialLastUpdated]);

  // Listener for live data broadcasts from the agent
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data?.stocks) {
        setStocks(data.stocks);
      }
      if (data?.lastUpdated) {
        setLastUpdated(data.lastUpdated);
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatTimestamp = (isoString?: string) => {
    if (!isoString) return 'Not available';
    try {
      return new Date(isoString).toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return isoString;
    }
  };

  return (
    <Box 
      background="var(--ggui-color-surface, #fafafa)" 
      paddingY={32} 
      style={{ minHeight: '100vh' }}
    >
      <MotionKeyframes />
      <Container maxWidth="xl">
        <Stack gap={32}>
          {/* Header Section */}
          <Stack direction="horizontal" align="end" justify="between" wrap>
            <Stack gap={4}>
              <Heading level={2}>Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Real-time market insights and stock performance
              </Text>
            </Stack>
            <Box paddingY={8}>
              <Stack direction="horizontal" gap={8} align="center">
                <Icon 
                  name="settings" 
                  size={14} 
                  color="var(--ggui-color-neutral-400, #9ca3af)" 
                />
                <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated: {formatTimestamp(lastUpdated)}
                </Text>
              </Stack>
            </Box>
          </Stack>

          {/* Connection Status Indicator */}
          {isConnecting && (
            <Box 
              background="var(--ggui-color-info-50, #ecfeff)" 
              padding={12} 
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{ border: '1px solid var(--ggui-color-info-200, #a5f3fc)' }}
            >
              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="bodySmall" color="var(--ggui-color-info-700, #0e7490)">
                  Connecting to live market feed...
                </Text>
              </Stack>
            </Box>
          )}

          {/* Stocks Grid */}
          {stocks.length > 0 ? (
            <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={20}>
              {stocks.map((stock, index) => {
                const isPositive = (stock.change ?? 0) >= 0;
                const statusColor = isPositive 
                  ? 'var(--ggui-color-success-600, #16a34a)' 
                  : 'var(--ggui-color-error-600, #dc2626)';
                const bgColor = isPositive 
                  ? 'var(--ggui-color-success-50, #f0fdf4)' 
                  : 'var(--ggui-color-error-50, #fef2f2)';
                const borderColor = isPositive
                  ? 'var(--ggui-color-success-200, #bbf7d0)'
                  : 'var(--ggui-color-error-200, #fecaca)';

                return (
                  <Card 
                    key={`${stock.symbol}-${index}`} 
                    padding={24} 
                    shadow="sm"
                    style={{ 
                      animation: `ggui-slideInUp 400ms ease-out ${index * 50}ms both`,
                      borderLeft: `4px solid ${statusColor}`,
                      transition: 'transform 200ms ease, box-shadow 200ms ease',
                      cursor: 'default'
                    }}
                  >
                    <Stack gap={16}>
                      <Stack direction="horizontal" justify="between" align="start">
                        <Stack gap={2}>
                          <Text weight="bold" size="xl" color="var(--ggui-color-onSurface, #18181b)">
                            {stock.symbol ?? '---'}
                          </Text>
                          <Text variant="caption" truncate color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {stock.name ?? 'Unknown Company'}
                          </Text>
                        </Stack>
                        <Badge variant={isPositive ? 'success' : 'error'} size="sm">
                          {isPositive ? 'Gain' : 'Loss'}
                        </Badge>
                      </Stack>

                      <Box>
                        <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                          ${stock.price?.toFixed(2) ?? '0.00'}
                        </Text>
                      </Box>

                      <Box 
                        padding={8} 
                        background={bgColor} 
                        borderRadius="var(--ggui-shape-radius-md, 8px)"
                        style={{ border: `1px solid ${borderColor}` }}
                      >
                        <Stack direction="horizontal" gap={4} align="center">
                          <Icon 
                            name={isPositive ? "chevron-up" : "chevron-down"} 
                            size={16} 
                            color={statusColor} 
                          />
                          <Text weight="semibold" size="sm" color={statusColor}>
                            {stock.change && stock.change > 0 ? '+' : ''}{stock.change?.toFixed(2) ?? '0.00'}
                          </Text>
                          <Spacer size={4} />
                          <Text size="xs" weight="medium" color={statusColor} style={{ opacity: 0.8 }}>
                            ({stock.changePercent?.toFixed(2) ?? '0.00'}%)
                          </Text>
                        </Stack>
                      </Box>
                    </Stack>
                  </Card>
                );
              })}
            </CardGrid>
          ) : (
            <Card padding={48} shadow="none" border={false}>
              <Stack align="center" gap={16}>
                <Icon name="search" size={48} color="var(--ggui-color-neutral-300, #d1d5db)" />
                <Stack align="center" gap={4}>
                  <Text weight="medium">No stock data available</Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    We're currently waiting for market data to load.
                  </Text>
                </Stack>
              </Stack>
            </Card>
          )}
        </Stack>
      </Container>
    </Box>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Input,
  Select,
  Toggle,
  Button,
  Divider,
  Progress,
  Avatar,
  Spacer,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback on completion */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"],
  roleOptions = ["Developer", "Designer", "Manager", "Other"],
  onComplete
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0] ?? '',
    role: initialProfile.role ?? '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light'
  });

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const isStep1Valid = formData.name.trim().length > 0 && validateEmail(formData.email);
  const isStep2Valid = formData.role !== '';

  const handleNext = () => {
    if (step < 3) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleSubmit = () => {
    onComplete?.(formData);
  };

  const progressValue = (step / 3) * 100;

  return (
    <Container maxWidth="sm" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header & Step Indicator */}
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="end">
            <Heading level={2}>Onboarding</Heading>
            <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500)">
              Step {step} of 3
            </Text>
          </Stack>
          <Progress value={progressValue} variant="default" size="md" />
        </Stack>

        <Card padding={32} shadow="md" radius="xl">
          <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }} key={step}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Display Name"
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => setFormData({ ...formData, name: val })}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData({ ...formData, email: val })}
                  required
                  error={formData.email && !validateEmail(formData.email) ? "Please enter a valid email" : undefined}
                />
                <Stack gap={8}>
                  <Text variant="label">Choose an Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map((emoji) => (
                      <Box
                        key={emoji}
                        padding={8}
                        borderRadius="var(--ggui-shape-radius-full)"
                        background={formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'transparent'}
                        style={{
                          cursor: 'pointer',
                          border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent',
                          transition: 'all 200ms ease'
                        }}
                        onClick={() => setFormData({ ...formData, avatar: emoji })}
                      >
                        <Text size="3xl">{emoji}</Text>
                      </Box>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="What is your role?"
                  value={formData.role}
                  onChange={(val) => setFormData({ ...formData, role: val })}
                  options={roleOptions.map(r => ({ label: r, value: r }))}
                  placeholder="Select a role"
                  required
                />
                <Divider />
                <Toggle
                  label="Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(checked) => setFormData({ ...formData, emailNotifications: checked })}
                />
                <Stack direction="horizontal" align="center" justify="between">
                  <Text variant="body">Theme Preference</Text>
                  <Stack direction="horizontal" gap={8} background="var(--ggui-color-neutral-100)" padding={4} borderRadius={8}>
                    <Button
                      size="sm"
                      variant={formData.theme === 'light' ? 'primary' : 'ghost'}
                      onClick={() => setFormData({ ...formData, theme: 'light' })}
                    >
                      Light
                    </Button>
                    <Button
                      size="sm"
                      variant={formData.theme === 'dark' ? 'primary' : 'ghost'}
                      onClick={() => setFormData({ ...formData, theme: 'dark' })}
                    >
                      Dark
                    </Button>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={4}>Review & Confirm</Heading>
                <Box background="var(--ggui-color-primary-50)" padding={20} borderRadius={12}>
                  <Stack direction="horizontal" gap={16} align="center">
                    <Avatar name={formData.name} size="xl" src="" />
                    <Stack gap={4}>
                      <Text variant="bodyLarge" weight="bold">{formData.name}</Text>
                      <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">{formData.email}</Text>
                    </Stack>
                    <Spacer size="flex" />
                    <Text size="4xl">{formData.avatar}</Text>
                  </Stack>
                </Box>

                <Stack gap={12}>
                  <Stack direction="horizontal" justify="between">
                    <Text color="var(--ggui-color-neutral-500)">Role</Text>
                    <Text weight="medium">{formData.role}</Text>
                  </Stack>
                  <Stack direction="horizontal" justify="between">
                    <Text color="var(--ggui-color-neutral-500)">Notifications</Text>
                    <Text weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  </Stack>
                  <Stack direction="horizontal" justify="between">
                    <Text color="var(--ggui-color-neutral-500)">Theme</Text>
                    <Text weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                  </Stack>
                </Stack>
              </Stack>
            )}
          </div>
        </Card>

        {/* Footer Navigation */}
        <Stack direction="horizontal" justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
            leftIcon={<span>←</span>}
          >
            Back
          </Button>

          {step < 3 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={step === 1 ? !isStep1Valid : !isStep2Valid}
              rightIcon={<span>→</span>}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

