import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Input, 
  TextArea, 
  RadioGroup, 
  Checkbox,
  Progress
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (data: any) => void;
}

export default function GeneratedComponent({ 
  featureOptions = ["Dashboard Analytics", "Team Collaboration", "API Integration", "Custom Workflows", "Mobile App", "AI Assistance"],
  satisfactionLabels = ["Very Unsatisfied", "Unsatisfied", "Neutral", "Satisfied", "Very Satisfied"],
  onSubmit 
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({ name: '', email: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateStep = () => {
    if (step === 1) {
      const newErrors = {
        name: formData.name ? '' : 'Name is required',
        email: validateEmail(formData.email) ? '' : 'Valid email is required'
      };
      setErrors(newErrors);
      return !newErrors.name && !newErrors.email;
    }
    return true;
  };

  const handleNext = () => {
    if (validateStep()) setStep(s => s + 1);
  };

  const handleBack = () => setStep(s => s - 1);

  const toggleFeature = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature) 
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  const submitForm = () => {
    setIsSubmitting(true);
    onSubmit({
      ...formData,
      satisfaction: formData.satisfaction === 0 ? null : formData.satisfaction
    });
  };

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Input 
              label="Name" 
              required 
              value={formData.name} 
              onChange={(v) => { setFormData(p => ({...p, name: v})); setErrors(e => ({...e, name: ''})) }} 
              error={errors.name} 
            />
            <Input 
              label="Email" 
              required 
              type="email" 
              value={formData.email} 
              onChange={(v) => { setFormData(p => ({...p, email: v})); setErrors(e => ({...e, email: ''})) }} 
              error={errors.email} 
            />
          </Stack>
        );
      case 2:
        return (
          <RadioGroup 
            label="How satisfied are you?" 
            value={formData.satisfaction?.toString() || ''} 
            onChange={(v) => setFormData(p => ({...p, satisfaction: parseInt(v)}))}
            options={satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))}
          />
        );
      case 3:
        return (
          <Stack gap={12}>
            <Text variant="label">Feature Interests</Text>
            {featureOptions.map(f => (
              <Checkbox 
                key={f} 
                label={f} 
                checked={formData.features.includes(f)} 
                onChange={() => toggleFeature(f)} 
              />
            ))}
          </Stack>
        );
      case 4:
        return (
          <TextArea 
            label="Comments (optional)" 
            value={formData.comments} 
            onChange={(v) => setFormData(p => ({...p, comments: v}))} 
            maxLength={500} 
            showCount 
          />
        );
      case 5:
        return (
          <Stack gap={12}>
            <Heading level={4}>Review Your Answers</Heading>
            <Text><strong>Name:</strong> {formData.name}</Text>
            <Text><strong>Email:</strong> {formData.email}</Text>
            <Text><strong>Satisfaction:</strong> {formData.satisfaction ? satisfactionLabels[formData.satisfaction - 1] : 'N/A'}</Text>
            <Text><strong>Features:</strong> {formData.features.join(', ') || 'None'}</Text>
            <Text><strong>Comments:</strong> {formData.comments || 'No comments'}</Text>
          </Stack>
        );
    }
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24}>
        <Stack gap={24}>
          <Stack gap={8}>
            <Text variant="overline">Step {step} of 5</Text>
            <Progress value={(step / 5) * 100} />
          </Stack>

          {renderStep()}

          <Stack direction="horizontal" gap={8} justify="between">
            <Button variant="ghost" disabled={step === 1 || isSubmitting} onClick={handleBack}>Back</Button>
            {step < 5 ? (
              <Button onClick={handleNext}>Next</Button>
            ) : (
              <Button variant="primary" loading={isSubmitting} onClick={submitForm}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Select, Badge, Avatar, Divider, Box } from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks?: Task[];
  columns?: Column[];
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    tasks = [], 
    columns = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' }
    ],
    onTaskUpdate 
  } = props;

  const [taskList, setTaskList] = useState<Task[]>(tasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTask, setNewTask] = useState({ title: '', priority: 'medium' as 'low' | 'medium' | 'high' });

  useEffect(() => {
    setTaskList(tasks);
  }, [tasks]);

  const totalTasks = taskList.length;
  const completedTasks = taskList.filter(t => t.column === 'done').length;

  const handleTaskAction = (action: string, taskId: string | undefined, data: any) => {
    if (action === 'move') {
      setTaskList(prev => prev.map(t => t.id === taskId ? { ...t, ...data } : t));
    }
    if (onTaskUpdate) onTaskUpdate({ action, taskId, data });
  };

  const handleAddTask = (columnId: string) => {
    const newTaskObj: Task = {
      id: Date.now().toString(),
      title: newTask.title || 'New Task',
      priority: newTask.priority,
      column: columnId,
      assignee: '??'
    };
    setTaskList([...taskList, newTaskObj]);
    setAddingTo(null);
    setNewTask({ title: '', priority: 'medium' });
    if (onTaskUpdate) onTaskUpdate({ action: 'create', taskId: newTaskObj.id, data: newTaskObj });
  };

  return (
    <Box padding={24}>
      <Stack gap={24}>
        <Card padding={16} shadow="md">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Project Board</Heading>
            <Text variant="label">{completedTasks} / {totalTasks} Tasks Completed</Text>
          </Stack>
        </Card>

        <Stack direction="horizontal" gap={16} align="start" wrap={true}>
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-neutral-100)" borderRadius={8} padding={12} style={{ width: '300px', flexShrink: 0 }}>
              <Stack gap={12}>
                <Heading level={4}>{col.name} ({taskList.filter(t => t.column === col.id).length})</Heading>

                <Stack gap={8}>
                  {taskList.filter(t => t.column === col.id).map(task => (
                    <Card key={task.id} padding={12} shadow="sm">
                      <Stack gap={8}>
                        <Text weight="medium">{task.title}</Text>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'}>
                            {task.priority}
                          </Badge>
                          <Avatar name={task.assignee || '??'} size={24} />
                        </Stack>
                        <Divider />
                        <Select 
                          value={task.column ?? ''} 
                          onChange={(val) => handleTaskAction('move', task.id, { column: val })}
                          options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingTo === col.id ? (
                  <Card padding={12} shadow="md">
                    <Stack gap={8}>
                      <Input label="Title" value={newTask.title} onChange={(v) => setNewTask({...newTask, title: v})} />
                      <Select label="Priority" value={newTask.priority} onChange={(v) => setNewTask({...newTask, priority: v as any})} options={[{value:'low', label:'Low'}, {value:'medium', label:'Medium'}, {value:'high', label:'High'}]} />
                      <Button onClick={() => handleAddTask(col.id)}>Add Task</Button>
                      <Button variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setAddingTo(col.id)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Box>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input, Divider } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<ElementData>;
}

const getCategoryColor = (category?: string) => {
  switch (category) {
    case 'noble-gas': return 'var(--ggui-color-primary-200, #bae6fd)';
    case 'nonmetal': return 'var(--ggui-color-success-100, #dcfce7)';
    case 'alkali-metal': return 'var(--ggui-color-warning-100, #fef3c7)';
    case 'halogen': return 'var(--ggui-color-info-100, #cffafe)';
    default: return 'var(--ggui-color-neutral-100, #f3f4f6)';
  }
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, searchTerm]);

  const categories = Array.from(new Set(elements.map((e) => e.category).filter(Boolean)));

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table of Elements</Heading>

        <Input
          label="Search Elements"
          placeholder="Enter element name or symbol (e.g., 'Hydrogen' or 'H')"
          value={searchTerm}
          onChange={setSearchTerm}
          type="search"
        />

        <Stack direction="horizontal" gap={16} wrap>
          {categories.map((cat) => (
            <Stack key={cat} direction="horizontal" gap={8} align="center">
              <Box background={getCategoryColor(cat)} borderRadius={4} padding={12} />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            marginTop: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {filteredElements.map((el) => (
            <button
              key={el.atomicNumber}
              onClick={() => setSelectedElement(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                background: getCategoryColor(el.category),
                border: selectedElement?.atomicNumber === el.atomicNumber 
                  ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                  : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                padding: '8px',
                cursor: 'pointer',
                transition: 'all 200ms ease',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                height: '80px',
                width: '100%',
              }}
              aria-label={`${el.name}, Atomic Number ${el.atomicNumber}`}
            >
              <Text variant="caption" style={{ alignSelf: 'flex-start' }}>
                {el.atomicNumber}
              </Text>
              <Text variant="bodyLarge" weight="bold">
                {el.symbol}
              </Text>
            </button>
          ))}
        </div>

        {selectedElement && (
          <Card padding={24} shadow="md">
            <Stack gap={8}>
              <Heading level={3}>
                {selectedElement.name} ({selectedElement.symbol})
              </Heading>
              <Divider />
              <Text variant="body">Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="body">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="body">Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Box, 
  Divider, 
  Badge, 
  Tabs, 
  Spinner 
} from '@ggui-ai/design/primitives';

/**
 * ProductDetailPage Component
 * 
 * E-commerce product detail page with tabbed specifications, reviews,
 * interactive quantity selector, and cart submission.
 */

interface ProductReview {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface ProductSpec {
  key: string;
  value: string;
}

interface Product {
  id?: string;
  name?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  stock?: number;
  description?: string;
  specifications?: ProductSpec[];
  reviews?: ProductReview[];
}

interface Props {
  product: Product;
  onAddToCart?: (payload: { productId: string; quantity: number }) => Promise<void>;
}

export default function ProductDetailPage({
  product = {
    id: "prod-001",
    name: "Product Name",
    price: 0,
    currency: "USD",
    rating: 0,
    reviewCount: 0,
    stock: 0,
    description: "No description available.",
    specifications: [],
    reviews: []
  },
  onAddToCart = async () => {}
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const { id = 'unknown', name, price, currency, rating = 0, stock = 0, description, specifications = [], reviews = [] } = product;

  const handleAddToCart = async () => {
    setLoading(true);
    setStatus(null);
    try {
      await onAddToCart({ productId: id, quantity });
      setStatus({ type: 'success', message: 'Added to cart successfully!' });
    } catch (e) {
      setStatus({ type: 'error', message: 'Failed to add to cart. Please try again.' });
    } finally {
      setLoading(false);
    }
  };

  const getStockBadge = () => {
    if (stock <= 0) return { variant: "error" as const, label: "Out of Stock" };
    if (stock <= 5) return { variant: "warning" as const, label: `Low Stock (${stock})` };
    return { variant: "success" as const, label: `In Stock (${stock})` };
  };

  const stockBadge = getStockBadge();

  const renderStars = (rate: number) => {
    return (
      <Box role="img" aria-label={`${rate} out of 5 stars`} style={{ display: 'flex', gap: '2px' }}>
        {Array.from({ length: 5 }).map((_, i) => (
          <Text key={i} color={i < Math.floor(rate) ? "var(--ggui-color-warning-500)" : "var(--ggui-color-neutral-300)"}>
            ★
          </Text>
        ))}
      </Box>
    );
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={48}>
        {/* Top Section */}
        <Stack direction="horizontal" gap={32} wrap>
          <Box 
            background="var(--ggui-color-surfaceVariant)" 
            borderRadius={12} 
            padding={64} 
            style={{ flex: 1, minWidth: 300, textAlign: 'center', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
             <Heading level={3} color="var(--ggui-color-onSurfaceVariant)">{name ?? "Product Image"}</Heading>
          </Box>

          <Stack gap={16} style={{ flex: 1 }}>
            <Heading level={1}>{name}</Heading>

            <Stack direction="horizontal" gap={12} align="center" style={{ marginTop: '8px' }}>
              <Text variant="bodyLarge" weight="bold">{currency} {price?.toFixed(2)}</Text>
              {renderStars(rating)}
              <Text variant="caption">({product.reviewCount} reviews)</Text>
            </Stack>

            <Box>
              <Badge variant={stockBadge.variant}>{stockBadge.label}</Badge>
            </Box>

            <Divider margin={8} />

            {/* Controls */}
            <Stack direction="horizontal" gap={16} align="center">
              <Stack direction="horizontal" gap={4} align="center">
                <Button size="sm" variant="outline" onClick={() => setQuantity(q => Math.max(1, q - 1))} disabled={stock === 0}>-</Button>
                <Text>{quantity}</Text>
                <Button size="sm" variant="outline" onClick={() => setQuantity(q => Math.min(stock, q + 1))} disabled={stock === 0}>+</Button>
              </Stack>
              <Button 
                variant="primary" 
                size="md" 
                onClick={handleAddToCart} 
                disabled={stock === 0 || loading}
                loading={loading}
              >
                Add to Cart
              </Button>
            </Stack>

            {status && (
              <Text color={status.type === 'success' ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'}>
                {status.message}
              </Text>
            )}
          </Stack>
        </Stack>

        {/* Middle Section (Tabs) */}
        <Tabs
          variant="line"
          items={[
            {
              key: 'desc',
              label: 'Description',
              content: <Card padding={24}><Text>{description}</Text></Card>
            },
            {
              key: 'specs',
              label: 'Specifications',
              content: (
                <Card padding={24}>
                  {specifications.map((s, i) => (
                    <Box key={i} paddingY={8} style={{ display: 'flex', borderBottom: i < specifications.length - 1 ? '1px solid var(--ggui-color-outlineVariant)' : 'none' }}>
                      <Text weight="semibold" style={{ width: '40%' }}>{s.key}</Text>
                      <Text>{s.value}</Text>
                    </Box>
                  ))}
                </Card>
              )
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Stack gap={16}>
                  {reviews.map((r, i) => (
                    <Card key={i} padding={16}>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text weight="medium">{r.author}</Text>
                        <Text variant="caption">{r.date}</Text>
                      </Stack>
                      <Box style={{ marginTop: '4px' }}>{renderStars(r.rating)}</Box>
                      <Text variant="bodySmall" style={{ marginTop: 8 }}>{r.text}</Text>
                    </Card>
                  ))}
                </Stack>
              )
            }
          ]}
        />
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Input, Button, Divider, Spacer, Box } from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

export default function GeneratedComponent(props: Props) {
  const { title, currentUser, participantCount, messages: initialMessages = [] } = props;
  const [messages, setMessages] = useState(initialMessages);
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) {
        setMessages((prev) => [...prev, event.detail]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim()) return;
    const newMessage = {
      sender: currentUser,
      text: inputText,
      timestamp: new Date().toISOString(),
    };
    setMessages((prev) => [...prev, newMessage]);
    setInputText('');
  };

  return (
    <Card shadow="md" padding={0} style={{ display: 'flex', flexDirection: 'column', height: '500px', overflow: 'hidden' }}>
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-neutral-200)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Text weight="semibold">{title}</Text>
          {participantCount !== undefined && (
            <Text variant="caption">{participantCount} participants</Text>
          )}
        </Stack>
      </Box>

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }}>
        <Stack gap={16}>
          {messages.map((msg, i) => {
            const isOwn = msg.sender === currentUser || msg.sender === 'You';
            return (
              <Stack key={i} align={isOwn ? 'end' : 'start'}>
                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                  {msg.sender ?? 'Unknown'} • {new Date(msg.timestamp ?? '').toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </Text>
                <Box
                  paddingX={12}
                  paddingY={8}
                  borderRadius={8}
                  background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-neutral-100)'}
                >
                  <Text color={isOwn ? '#ffffff' : 'var(--ggui-color-neutral-900)'}>{msg.text}</Text>
                </Box>
              </Stack>
            );
          })}
        </Stack>
      </div>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-neutral-200)' }}>
        <Stack direction="horizontal" gap={8} align="end">
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              value={inputText}
              onChange={setInputText}
              placeholder="Type a message..."
              onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
            />
          </div>
          <Button 
            variant="primary" 
            onClick={handleSend} 
            disabled={!inputText.trim()}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Stack, Card, Text, Heading, Divider, Spinner, Box } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks?: Array<Stock>;
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const { stocks: initialStocks = [], lastUpdated: initialLastUpdated } = props;
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);

  useEffect(() => {
    const listener = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data && Array.isArray(data.stocks)) {
        setStocks(data.stocks);
        setLastUpdated(new Date().toISOString());
      }
    };

    document.addEventListener('ggui:agent-data', listener);
    return () => document.removeEventListener('ggui:agent-data', listener);
  }, []);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Text variant="caption" color="var(--ggui-color-neutral-500)">
            {lastUpdated ? `Last Updated: ${new Date(lastUpdated).toLocaleTimeString()}` : 'Initializing...'}
          </Text>
        </Stack>

        <Divider />

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
          gap: 'var(--ggui-spacing-4)'
        }}>
          {stocks.map((stock, idx) => {
            const change = stock.change ?? 0;
            const isPositive = change >= 0;
            const color = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';

            return (
              <Card key={idx} padding={20} shadow="sm">
                <Stack gap={12}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap={4}>
                      <Heading level={3}>{stock.symbol ?? '---'}</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">{stock.name ?? 'Unknown'}</Text>
                    </Stack>
                    <Box 
                      paddingX={8} 
                      paddingY={4} 
                      borderRadius={9999} 
                      background={isPositive ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)'}
                    >
                      <Text variant="caption" weight="semibold" color={color}>
                        {isPositive ? '▲' : '▼'} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                      </Text>
                    </Box>
                  </Stack>
                  <Stack direction="horizontal" align="end" gap={8}>
                    <Text size="3xl" weight="bold">${stock.price?.toFixed(2) ?? '0.00'}</Text>
                    <Text variant="body" weight="medium" color={color}>
                      {isPositive ? '+' : ''}{change.toFixed(2)}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Divider } from '@ggui-ai/design/primitives';
import { Button, Input, Select, Toggle, RadioGroup } from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  avatarOptions: string[];
  roleOptions: string[];
  complete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, complete } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0],
    role: initialProfile.role ?? roleOptions[0],
    emailNotifications: initialProfile.emailNotifications ?? false,
    theme: initialProfile.theme ?? 'light',
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const radioAvatarOptions = avatarOptions.map(emoji => ({ value: emoji, label: emoji }));

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24}>
        <Stack gap={16}>
          <Text variant="label">Step {step} of 3</Text>
          <Box background="var(--ggui-color-neutral-200)" borderRadius={4} paddingY={4}>
            <Box background="var(--ggui-color-primary-600)" borderRadius={4} paddingY={4} style={{ width: `${(step / 3) * 100}%` }} />
          </Box>

          {step === 1 && (
            <Stack gap={16}>
              <Heading level={3}>Profile Setup</Heading>
              <Input label="Name" value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} required />
              <Input label="Email" type="email" value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} required error={formData.email && !validateEmail(formData.email) ? "Invalid email" : undefined} />
              <RadioGroup label="Select Avatar" value={formData.avatar} onChange={(v) => setFormData({ ...formData, avatar: v })} options={radioAvatarOptions} direction="horizontal" />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={3}>Preferences</Heading>
              <Select label="Role" value={formData.role} onChange={(v) => setFormData({ ...formData, role: v })} options={roleOptions.map(r => ({ value: r, label: r }))} />
              <Toggle label="Enable Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} />
              <RadioGroup label="Theme" value={formData.theme} onChange={(v) => setFormData({ ...formData, theme: v })} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={3}>Review & Confirm</Heading>
              <Box background="var(--ggui-color-neutral-100)" padding={16} borderRadius={8}>
                <Stack gap={8}>
                  <Text>Name: {formData.name}</Text>
                  <Text>Email: {formData.email}</Text>
                  <Text>Avatar: {formData.avatar}</Text>
                  <Text>Role: {formData.role}</Text>
                  <Text>Notifications: {formData.emailNotifications ? 'On' : 'Off'}</Text>
                  <Text>Theme: {formData.theme}</Text>
                </Stack>
              </Box>
            </Stack>
          )}

          <Divider />

          <Stack direction="horizontal" gap={8} justify="between">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Go Back</Button>
            {step < 3 ? (
              <Button onClick={handleNext} disabled={step === 1 && !isStep1Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => complete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
